+import { createAdded, createChanged, createPredicate, createRemoved, createWorld, Not, Or, relation, trait } from '../src';
+
+describe('predicates', () => {
+    const Score = trait({ value: 0 });
+    const Other = trait({ value: 0 });
+
+    it('filters by dependency values and reacts to set and add', () => {
+        const HighScore = createPredicate([Score], ([score]) => score.value >= 10);
+        const world = createWorld();
+        const entity = world.spawn(Score({ value: 5 }));
+
+        expect(world.query(HighScore)).toEqual([]);
+        entity.set(Score, { value: 10 });
+        expect(world.query(HighScore)).toEqual([entity]);
+        entity.remove(Score);
+        expect(world.query(HighScore)).toEqual([]);
+        entity.add(Score({ value: 12 }));
+        expect(world.query(HighScore)).toEqual([entity]);
+    });
+
+    it('is excluded from callback data and supports Not, Or, and relation pairs', () => {
+        const HighScore = createPredicate([Score], ([score]) => score.value >= 10);
+        const ChildOf = relation();
+        const world = createWorld();
+        const parent = world.spawn();
+        const low = world.spawn(Score({ value: 2 }), ChildOf(parent));
+        const high = world.spawn(Score({ value: 12 }), ChildOf(parent));
+
+        expect(world.query(Not(HighScore))).toEqual([low]);
+        expect(world.query(Or(HighScore, Other), ChildOf(parent))).toEqual([high]);
+        world.query(HighScore).readEach((state) => expect(state).toEqual([]));
+    });
+
+    it('tracks predicate truthiness transitions', () => {
+        const HighScore = createPredicate([Score], ([score]) => score.value >= 10);
+        const Added = createAdded();
+        const Removed = createRemoved();
+        const Changed = createChanged();
+        const world = createWorld();
+        const entity = world.spawn(Score({ value: 5 }));
+
+        world.query(Added(HighScore));
+        world.query(Removed(HighScore));
+        world.query(Changed(HighScore));
+        entity.set(Score, { value: 12 });
+        expect(world.query(Added(HighScore))).toEqual([entity]);
+        expect(world.query(Removed(HighScore))).toEqual([]);
+        expect(world.query(Changed(HighScore))).toEqual([entity]);
